@app.route('/progress/<int:user_id>', methods=['GET'])
def get_user_progress(user_id):
    lists = get_lists_by_user(user_id)
    total_items = 0
    completed_items = 0
    for lst in lists:
        list_id = next((k for k, v in lists.items() if v == lst), None)
        items = get_items_by_list(list_id)
        total_items += len(items)
        completed_items += sum(1 for item in items if item['completed'])

    if total_items == 0:
        progress = 0
    else:
        progress = (completed_items / total_items) * 100

    return jsonify({'progress': progress, 'total_items': total_items, 'completed_items': completed_items})

@app.route('/reminders/<int:user_id>', methods=['GET'])
def get_user_reminders(user_id):
    lists = get_lists_by_user(user_id)
    reminders = []
    now = datetime.utcnow()

    for lst in lists:
        list_id = next((k for k, v in lists.items() if v == lst), None)
        items = get_items_by_list(list_id)
        for item in items:
            if item['due_date']:
                due_date = datetime.fromisoformat(item['due_date'].replace('Z', '+00:00'))
                if not item['completed']:
                    if due_date <= now:
                        reminders.append({'item_id': next((k for k, v in items.items() if v == item), None), 'item_text': item['item_text'], 'status': 'overdue'})
                    elif due_date <= now + timedelta(days=1):
                        reminders.append({'item_id': next((k for k, v in items.items() if v == item), None), 'item_text': item['item_text'], 'status': 'due soon'})

    return jsonify(reminders)

if __name__ == '__main__':
