    if total_items == 0:
        progress = 0
    else:
        progress = (completed_items / total_items) * 100

    return jsonify({'progress': progress})

@app.route('/reminders', methods=['GET'])
def get_reminders():
    """Returns reminders for due and overdue tasks."""
    all_lists = get_all_lists()
    reminders = []
    today = datetime.now().date()

    for todo_list in all_lists:
        list_data = get_list(todo_list["id"])
        if list_data:
            for item in list_data["items"]:
                if item["due_date"]:
                    due_date = datetime.strptime(item["due_date"], '%Y-%m-%d').date()
                    if not item["completed"]:
                        if due_date == today:
                            reminders.append(f"Item '{item['text']}' from list '{list_data['name']}' is due today!")
                        elif due_date < today:
                            reminders.append(f"Item '{item['text']}' from list '{list_data['name']}' is overdue!")

    return jsonify({'reminders': reminders})

