        except ValueError:
            abort(400, message="Invalid date format.  Please use YYYY-MM-DD.")

        new_item = create_item(list_id, args['description'], due_date)
        return new_item, 201

# Resource for marking an item as complete
class TodoItemCompleteResource(Resource):
