class TaskDB:
    def __init__(self):
        self.tasks = {}
        self.list_id_counter = 1
        self.task_id_counter = 1

    def create_list(self, name):
        list_id = self.list_id_counter
        self.tasks[list_id] = {"name": name, "items": []}
        self.list_id_counter += 1
        return list_id

    def get_list(self, list_id):
        if list_id not in self.tasks:
            return None
        return self.tasks[list_id]

    def update_list(self, list_id, name):
        if list_id not in self.tasks:
            return False
        self.tasks[list_id]["name"] = name
        return True

    def delete_list(self, list_id):
        if list_id not in self.tasks:
            return False
        del self.tasks[list_id]
        return True

    def create_task(self, list_id, description, due_date=None):
        if list_id not in self.tasks:
            return None
        task_id = self.task_id_counter
        task = {"id": task_id, "description": description, "completed": False, "due_date": due_date}
        self.tasks[list_id]["items"].append(task)
        self.task_id_counter += 1
        return task_id

    def get_task(self, list_id, task_id):
        if list_id not in self.tasks:
            return None
        for task in self.tasks[list_id]["items"]:
            if task["id"] == task_id:
                return task
        return None

    def update_task(self, list_id, task_id, description=None, completed=None, due_date=None):
        if list_id not in self.tasks:
            return False
        for task in self.tasks[list_id]["items"]:
            if task["id"] == task_id:
                if description is not None:
                    task["description"] = description
                if completed is not None:
                    task["completed"] = completed
                if due_date is not None:
                    task["due_date"] = due_date
                return True
        return False

    def delete_task(self, list_id, task_id):
        if list_id not in self.tasks:
            return False
        items = self.tasks[list_id]["items"]
        for i in range(len(items)):
            if items[i]["id"] == task_id:
                del items[i]
                return True
        return False

    def get_progress(self, list_id):
        if list_id not in self.tasks:
            return None
        items = self.tasks[list_id]["items"]
        total_tasks = len(items)
        completed_tasks = sum(1 for task in items if task["completed"])
        if total_tasks == 0:
            return 0
        return (completed_tasks / total_tasks) * 100

    def get_overdue_tasks(self, list_id):
        if list_id not in self.tasks:
            return None
        now = datetime.now()
        overdue_tasks = []
        for task in self.tasks[list_id]["items"]:
            if task["due_date"] and datetime.strptime(task["due_date"], "%Y-%m-%d") < now and not task["completed"]:
                overdue_tasks.append(task)
        return overdue_tasks

    def get_due_today_tasks(self, list_id):
        if list_id not in self.tasks:
            return None
        today = datetime.now().strftime("%Y-%m-%d")
        due_today_tasks = []
        for task in self.tasks[list_id]["items"]:
            if task["due_date"] == today and not task["completed"]:
                due_today_tasks.append(task)
        return due_today_tasks


