from flask import Flask, request, jsonify
from flask_restful import Resource, Api, reqparse
from datetime import datetime, timedelta

app = Flask(__name__)
api = Api(app)

# Dummy data (replace with database interaction)
todos = {}
items = {}  # Store items associated with each todo

# Request parsers for input validation
todo_parser = reqparse.RequestParser()
todo_parser.add_argument('title', type=str, required=True, help='Title is required')
todo_parser.add_argument('description', type=str, default='', help='Description')
todo_parser.add_argument('due_date', type=str, help='Due date (YYYY-MM-DD)')

item_parser = reqparse.RequestParser()
item_parser.add_argument('description', type=str, required=True, help='Item description is required')
item_parser.add_argument('completed', type=bool, default=False, help='Item completion status')


class Todo(Resource):
    def get(self, todo_id):
        if todo_id not in todos:
            return {'message': 'Todo not found'}, 404
        return todos[todo_id]

    def put(self, todo_id):
        if todo_id not in todos:
            return {'message': 'Todo not found'}, 404

        args = todo_parser.parse_args()
        todo = todos[todo_id]
        todo['title'] = args['title']
        todo['description'] = args['description']
        if args['due_date']:
            try:
                todo['due_date'] = datetime.strptime(args['due_date'], '%Y-%m-%d').date().isoformat()
            except ValueError:
                return {'message': 'Invalid date format. Use YYYY-MM-DD'}, 400
        else:
            todo['due_date'] = None

        todos[todo_id] = todo
        return todo

    def delete(self, todo_id):
        if todo_id not in todos:
            return {'message': 'Todo not found'}, 404
        del todos[todo_id]
        if todo_id in items:
            del items[todo_id] # Delete associated items
        return '', 204


class TodoList(Resource):
    def get(self):
        return todos

    def post(self):
        args = todo_parser.parse_args()
        todo_id = len(todos) + 1
        due_date = None
        if args['due_date']:
            try:
                due_date = datetime.strptime(args['due_date'], '%Y-%m-%d').date().isoformat()
            except ValueError:
                return {'message': 'Invalid date format. Use YYYY-MM-DD'}, 400

        todo = {
            'id': todo_id,
            'title': args['title'],
            'description': args['description'],
            'due_date': due_date
        }
        todos[todo_id] = todo
        items[todo_id] = {} # Initialize items for the new todo
        return todo, 201


class TodoItem(Resource):
    def get(self, todo_id, item_id):
        if todo_id not in items or item_id not in items[todo_id]:
            return {'message': 'Item not found'}, 404
        return items[todo_id][item_id]

    def put(self, todo_id, item_id):
        if todo_id not in items or item_id not in items[todo_id]:
            return {'message': 'Item not found'}, 404

        args = item_parser.parse_args()
        item = items[todo_id][item_id]
        item['description'] = args['description']
        item['completed'] = args['completed']
        items[todo_id][item_id] = item
        return item

    def delete(self, todo_id, item_id):
        if todo_id not in items or item_id not in items[todo_id]:
            return {'message': 'Item not found'}, 404
        del items[todo_id][item_id]
        return '', 204


class TodoItemList(Resource):
    def get(self, todo_id):
        if todo_id not in items:
            return {'message': 'Todo not found'}, 404
        return items[todo_id]

    def post(self, todo_id):
        if todo_id not in todos:
            return {'message': 'Todo not found'}, 404

        args = item_parser.parse_args()
        item_id = len(items[todo_id]) + 1
        item = {
            'id': item_id,
            'description': args['description'],
            'completed': args['completed']
        }
        items[todo_id][item_id] = item
        return item, 201


class Progress(Resource):
    def get(self):
        total_todos = len(todos)
        completed_todos = 0
        total_items = 0
        completed_items = 0

        for todo_id in todos:
            all_items_completed = True
            if todo_id in items:
                for item_id in items[todo_id]:
                    total_items += 1
                    if items[todo_id][item_id]['completed']:
                        completed_items += 1
                    else:
                        all_items_completed = False
            else:
                all_items_completed = False #Consider todo incomplete if no items

            if all_items_completed and todo_id in items:
                completed_todos += 1
            elif todo_id not in items and todos[todo_id]['description'] == "": #Consider todo complete if no items and no description
                completed_todos += 1

        todo_progress = (completed_todos / total_todos) * 100 if total_todos > 0 else 0
        item_progress = (completed_items / total_items) * 100 if total_items > 0 else 0

        return {
            'total_todos': total_todos,
            'completed_todos': completed_todos,
            'todo_progress': round(todo_progress, 2),
            'total_items': total_items,
            'completed_items': completed_items,
            'item_progress': round(item_progress, 2)
        }


class Reminders(Resource):
    def get(self):
        reminders = []
        today = datetime.now().date()

        for todo_id, todo in todos.items():
            if todo['due_date']:
                due_date = datetime.strptime(todo['due_date'], '%Y-%m-%d').date()
                time_difference = (due_date - today).days

                if time_difference == 0:
                    reminders.append({
                        'todo_id': todo_id,
