            try:
                due_date = datetime.strptime(due_date_str, "%Y-%m-%d").date()
            except ValueError:
                continue # Skip if date format is invalid

            if not item["completed"]:
                if due_date < today:
                    reminders.append({"list_title": todo_list["title"], "item_description": item["description"], "status": "overdue", "due_date": due_date_str})
                elif due_date == today:
                    reminders.append({"list_title": todo_list["title"], "item_description": item["description"], "status": "due today", "due_date": due_date_str})
                elif (due_date - today).days <= 2:
                    reminders.append({"list_title": todo_list["title"], "item_description": item["description"], "status": "upcoming", "due_date": due_date_str})

    return reminders


