from flask import Flask, request, jsonify
from flask_restful import Resource, Api, reqparse
from datetime import datetime, timedelta

app = Flask(__name__)
api = Api(app)

# Simulate a database (replace with a real database in a production environment)
todos = {}
items = {}  # Store items separately, linked to todo lists by todo_id

# Argument parsers for request validation
todo_parser = reqparse.RequestParser()
todo_parser.add_argument('title', type=str, required=True, help='Title is required')
todo_parser.add_argument('description', type=str, default='')

item_parser = reqparse.RequestParser()
item_parser.add_argument('description', type=str, required=True, help='Description is required')
item_parser.add_argument('due_date', type=str, help='Due date (YYYY-MM-DD)')
item_parser.add_argument('completed', type=bool, default=False)


class TodoList(Resource):
    def get(self):
        """Returns a list of all todo lists."""
        return todos

    def post(self):
        """Creates a new todo list."""
        args = todo_parser.parse_args()
        todo_id = len(todos) + 1
        todos[todo_id] = {'title': args['title'], 'description': args['description']}
        return {'message': 'Todo list created', 'todo_id': todo_id}, 201


class Todo(Resource):
    def get(self, todo_id):
        """Returns a specific todo list."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404

        todo_data = todos[todo_id]
        todo_items = [item for item_id, item in items.items() if item['todo_id'] == todo_id]

        todo_data['items'] = todo_items
        return todo_data

    def put(self, todo_id):
        """Updates a specific todo list."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404
        args = todo_parser.parse_args()
        todos[todo_id] = {'title': args['title'], 'description': args['description']}
        return {'message': 'Todo list updated'}

    def delete(self, todo_id):
        """Deletes a specific todo list and its associated items."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404
        del todos[todo_id]

        # Delete associated items
        item_ids_to_delete = [item_id for item_id, item in items.items() if item['todo_id'] == todo_id]
        for item_id in item_ids_to_delete:
            del items[item_id]

        return {'message': 'Todo list and associated items deleted'}


class ItemList(Resource):
    def get(self, todo_id):
        """Returns a list of items for a specific todo list."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404

        todo_items = [item for item_id, item in items.items() if item['todo_id'] == todo_id]
        return todo_items

    def post(self, todo_id):
        """Creates a new item for a specific todo list."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404

        args = item_parser.parse_args()
        item_id = len(items) + 1

        try:
            due_date = datetime.strptime(args['due_date'], '%Y-%m-%d').date() if args['due_date'] else None
        except ValueError:
            return {'message': 'Invalid date format. Use YYYY-MM-DD.'}, 400

        items[item_id] = {
            'todo_id': todo_id,
            'description': args['description'],
            'due_date': str(due_date) if due_date else None,
            'completed': args['completed']
        }
        return {'message': 'Item created', 'item_id': item_id}, 201


class Item(Resource):
    def get(self, todo_id, item_id):
        """Returns a specific item."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404
        if item_id not in items:
            return {'message': 'Item not found'}, 404
        if items[item_id]['todo_id'] != todo_id:
            return {'message': 'Item does not belong to this todo list'}, 400
        return items[item_id]

    def put(self, todo_id, item_id):
        """Updates a specific item."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404
        if item_id not in items:
            return {'message': 'Item not found'}, 404
        if items[item_id]['todo_id'] != todo_id:
            return {'message': 'Item does not belong to this todo list'}, 400

        args = item_parser.parse_args()

        try:
            due_date = datetime.strptime(args['due_date'], '%Y-%m-%d').date() if args['due_date'] else None
        except ValueError:
            return {'message': 'Invalid date format. Use YYYY-MM-DD.'}, 400

        items[item_id] = {
            'todo_id': todo_id,
            'description': args['description'],
            'due_date': str(due_date) if due_date else None,
            'completed': args['completed']
        }
        return {'message': 'Item updated'}

    def delete(self, todo_id, item_id):
        """Deletes a specific item."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404
        if item_id not in items:
            return {'message': 'Item not found'}, 404
        if items[item_id]['todo_id'] != todo_id:
            return {'message': 'Item does not belong to this todo list'}, 400
        del items[item_id]
        return {'message': 'Item deleted'}


class Progress(Resource):
    def get(self, todo_id):
        """Returns the progress of a specific todo list."""
        if todo_id not in todos:
            return {'message': 'Todo list not found'}, 404

        todo_items = [item for item_id, item in items.items() if item['todo_id'] == todo_id]
        total_items = len(todo_items)
        completed_items = sum(1 for item in todo_items if item['completed'])

        if total_items == 0:
            progress = 0
        else:
            progress = (completed_items / total_items) * 100

        return {'progress': progress, 'total_items': total_items, 'completed_items': completed_items}


class Reminders(Resource):
    def get(self):
        """Returns reminders for overdue and upcoming items."""
        today = datetime.now().date()
        overdue_items = []
        upcoming_items = []

        for item_id, item in items.items():
            if item['due_date']:
                due_date = datetime.strptime(item['due_date'], '%Y-%m-%d').date()
                if due_date < today and not item['completed']:
                    overdue_items.append({
                        'item_id': item_id,
                        'todo_id': item['todo_id'],
                        'description': item['description'],
                        'due_date': item['due_date']
                    })
                elif today <= due_date <= today + timedelta(days=7) and not item['completed']:
                    upcoming_items.append({
                        'item_id': item_id,
                        'todo_id': item['todo_id'],
                        'description': item['description'],
                        'due_date': item['due_date']
                    })

        return {'overdue': overdue_items, 'upcoming': upcoming_items}


