        """Returns a list of all todo lists."""
        return todos

    def post(self):
        """Creates a new todo list."""
        args = todo_parser.parse_args()
        todo_id = len(todos) + 1
        todos[todo_id] = {'id': todo_id, 'title': args['title'], 'description': args['description']}
        items[todo_id] = []  # Initialize item list for the new todo
        return todos[todo_id], 201


