        if todo_id not in todos:
            return {'message': 'Todo not found'}, 404
        del todos[todo_id]
        del items[todo_id] # Also delete associated items
        return '', 204


class TodoItem(Resource):
    def get(self, todo_id, item_id):
        """Returns a specific item in a todo list."""
        if todo_id not in items:
            return {'message': 'Todo list not found'}, 404
        if item_id > len(items[todo_id]) or item_id <= 0:
            return {'message': 'Item not found'}, 404

        # Items are stored as a list, so access by index (item_id - 1)
        return items[todo_id][item_id - 1]

    def post(self, todo_id):
        """Adds a new item to a todo list."""
        if todo_id not in items:
            return {'message': 'Todo list not found'}, 404

        args = item_parser.parse_args()
        item_id = len(items[todo_id]) + 1
        new_item = {
            'id': item_id,
            'description': args['description'],
            'due_date': args['due_date'],
            'completed': args['completed']
        }
        items[todo_id].append(new_item)
        return new_item, 201

    def put(self, todo_id, item_id):
        """Updates a specific item in a todo list."""
        if todo_id not in items:
            return {'message': 'Todo list not found'}, 404
        if item_id > len(items[todo_id]) or item_id <= 0:
            return {'message': 'Item not found'}, 404

        args = item_parser.parse_args()
        updated_item = {
            'id': item_id,
            'description': args['description'],
            'due_date': args['due_date'],
            'completed': args['completed']
        }
        items[todo_id][item_id - 1] = updated_item
        return updated_item

    def delete(self, todo_id, item_id):
        """Deletes a specific item from a todo list."""
        if todo_id not in items:
            return {'message': 'Todo list not found'}, 404
        if item_id > len(items[todo_id]) or item_id <= 0:
            return {'message': 'Item not found'}, 404

        del items[todo_id][item_id - 1]
        # Re-index items after deletion to maintain correct IDs
        for i in range(item_id - 1, len(items[todo_id])):
            items[todo_id][i]['id'] = i + 1
        return '', 204


